insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='PEREZ'and apellido2='SANTOS'),'2018-01-22','(Pedro)Asistencia a Juicio en Juzgado de lo Penal nº 1 de Plasencia.PA 0000522/2017. +++Sentencia: 19 meses de prisión al encausado, D. J.P.M., suspensiva si no delinque durante los tres años siguientes y no deja de pagar las mensulaidades correspondientes a la indemnización de 777€ que debe pagar a Dª Josefa, a razón de 7 mensualidades de 100€ y 1 mensualidad de 77€. +++Al final del acto se indica el nº de cuenta en la que realizar el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2018-01-23','Correo-e: +++Buen día, soy Sole la Trabajadora Social del Comedor Social Virgen de la Acogida de Badajoz. Me gustaría contactar con ustedes para hablarle de Jonatan Ramirez Juarez ,persona tutelada por la Junta de Extremadura y que es usuaria del comedor y del dispositivo de Ola de frio desde diciembre de 2017. Mi teléfono es el 924221773. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Contacto con Paqui, de SS Penitenciarios. +++No se ha cumplido la pena de 50 jornadas de trabajos en beneficio de la Comunidad. No pueden reabrir el caso hasta que no lo pida el Juzgado de lo Penal nº 1 de Mérida. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Contacto con el penal 1 de Mérida. No está la compañera que lleva el caso. +++ENVIAR escrito al JUZGADO de lo penal Nº 1 de MÉRIDA (924-388764/65/72), EJECUTORIA 106/2016 comunicando la localización actual de Jonathan: COMEDOR SOCIAL "VIRGEN de la CARIDAD". DIRECCIÓN:Martín Cansado Nº40, Badajoz.Se encuentra allí desde diciembre, como usuario del comedor social y del dispositivo "Ola de Frío". +++Sole comenta que quiere instalarse en Badajoz, porque ha conocido a unos "colegas". Al parecer tiene consumo activo y, aunque le ha dicho en varias ocasiones que se ponga en contacto con nosotros, no lo ha hecho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SIXTO NICANOR'and edp.apellido1='ALMODOVAR'and apellido2='JIMENEZ'),'2018-01-22','(Pedro)El CSS de Mérida comunica el traslado de D. Sixto al Hospital de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2018-01-23','CRR de Plasencia: +++Continua tratamiento para Hepatitis C. +++Ha llamado al 112 por un episodio en el que, agobiado por la sensación de malestar y de falta de aire. Tras valoración, le derivan a C. de salud para tratamiento por enfermedad común. +++Llamó a sus hermanas angustiado y éstas pensaron que estaba grave. Hablamos con ellas y tranquilizamos, pero os lo comunico por si contactan con vosotros, que podáis saber lo ocurrido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2018-01-23','Iciar: Llama de nuevo la madre para confirmar que nos ha llegado el fax con la carta de Hacienda. Efectivamente así ha sido, la tiene Alberto.','2');
